import { describe, expect, it } from 'vitest';
import {
  inferCaptureIqFormatFromPath,
  normalizeCaptureToRtlU8,
} from './capture-formats';

describe('capture format normalization', () => {
  it('infers signed_iq8 from .cs8/.s8 and rtl_u8 otherwise', () => {
    expect(inferCaptureIqFormatFromPath('/tmp/a.cs8')).toBe('signed_iq8');
    expect(inferCaptureIqFormatFromPath('/tmp/a.s8')).toBe('signed_iq8');
    expect(inferCaptureIqFormatFromPath('/tmp/a.cu8')).toBe('rtl_u8');
    expect(inferCaptureIqFormatFromPath('/tmp/a.u8')).toBe('rtl_u8');
  });

  it('normalizes signed iq8 bytes to rtl_u8 with xor 0x80', () => {
    const signed = Uint8Array.from([0x00, 0x80, 0x7f, 0xff]);
    const norm = normalizeCaptureToRtlU8(signed, 'signed_iq8');
    expect(Array.from(norm)).toEqual([0x80, 0x00, 0xff, 0x7f]);
  });

  it('rejects odd-length captures', () => {
    expect(() =>
      normalizeCaptureToRtlU8(Uint8Array.from([1, 2, 3]), 'rtl_u8'),
    ).toThrow(/even/);
  });
});
